const items = $input.all();

return items.map(item => {
  const data = item.json;
  const firstName   = (data.first_name || 'there').trim();
  const email       = (data.email     || '').trim();
  const sessionId   = data.session_id;
  const contactId   = data.contact_id;
  const scheduledAt = new Date(data.scheduled_at);

  const dateStr = scheduledAt.toLocaleDateString('en-US', {
    weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
    timeZone: 'America/New_York'
  });

  const testimonialsUrl = 'https://soul-synergy-hub.pages.dev/testimonials';

  const html = [
    '<div style="font-family:sans-serif;max-width:600px;margin:0 auto">',
    '<h2 style="color:#2D6A6A;margin-bottom:16px">\u2764\uFE0F How Was Your Session?</h2>',
    '<p style="line-height:1.7;color:#333">Hi ' + firstName + ',</p>',
    '<p style="line-height:1.7;color:#333">I hope you\'ve had time to reflect on our coaching session on <strong>' + dateStr + '</strong>. It was a privilege working with you, and I\'d love to hear how it landed for you.</p>',
    '<p style="line-height:1.7;color:#333">If you found our time together valuable, would you be willing to share a few words? Your feedback means the world — both to me personally, and to others who are considering taking the first step on their own journey.</p>',
    '<div style="text-align:center;margin:32px 0">',
    '<a href="' + testimonialsUrl + '" style="background:#2D6A6A;color:#fff;text-decoration:none;padding:14px 28px;border-radius:6px;font-size:15px;font-weight:600;display:inline-block">Share Your Feedback</a>',
    '</div>',
    '<p style="line-height:1.7;color:#333">It takes just a couple of minutes, and your words genuinely help others find the courage to invest in themselves.</p>',
    '<p style="line-height:1.7;color:#333">Thank you so much — I\'m grateful for you.</p>',
    '<p style="line-height:1.7;color:#333">With warmth,<br><strong>Arushi Bhardwaj</strong><br>SoulSynergy Coaching</p>',
    '<hr style="border:none;border-top:1px solid #eee;margin:24px 0">',
    '<p style="color:#999;font-size:12px">SoulSynergy Coaching &mdash; Uncover. Align. Achieve.</p>',
    '</div>'
  ].join('');

  const resendPayload = JSON.stringify({
    from: 'SoulSynergy Coaching <onboarding@resend.dev>',
    to: [email],
    subject: '\u2764\uFE0F ' + firstName + ', how was your coaching session?',
    html: html
  });

  return {
    json: {
      session_id:     sessionId,
      contact_id:     contactId,
      email:          email,
      resend_payload: resendPayload
    }
  };
});
